import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { useNavigate, Link } from 'react-router-dom';
import { fetchLiveMetalsPrices, MetalsData } from '../services/metalsApi';
import { yfinanceService, StockData } from '../services/yfinanceService';
import PriceTrendChart from '../components/PriceTrendChart';
import { getStaticHistoricalData } from '../services/staticHistoricalData';
import MarketPulse from '../components/MarketPulse';
import MutualFunds from '../components/MutualFunds';

const HomeContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 1rem 0;
`;

const HeroSection = styled(motion.section)`
  display: grid;
  grid-template-columns: 2.5fr 1fr;
  gap: 2rem;
  margin-bottom: 4rem;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
  }
`;

const GlassCard = styled(motion.div)`
  background: ${props => props.theme.colors.cardBackground};
  border-radius: ${props => props.theme.borderRadius.large};
  padding: 2rem;
  border: 1px solid ${props => props.theme.colors.border};
  backdrop-filter: blur(12px);
  box-shadow: ${props => props.theme.shadows.card};
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent);
  }
`;

const MainCard = styled(GlassCard)`
  padding: 2.5rem;
`;

const SidebarCard = styled(GlassCard)`
  padding: 1.5rem;
  background: rgba(255, 255, 255, 0.02);
`;

const SectionTitle = styled.h2`
  font-size: 1.5rem;
  font-weight: 700;
  margin-bottom: 2rem;
  letter-spacing: -0.5px;
  display: flex;
  align-items: center;
  gap: 0.8rem;
  color: ${props => props.theme.colors.textPrimary};

  span {
    color: ${props => props.theme.colors.textSecondary};
    font-size: 0.9rem;
    font-weight: 400;
  }
`;

const MarketGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1.5rem;
  margin-bottom: 3rem;

  @media (max-width: 1024px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 640px) {
    grid-template-columns: 1fr;
  }
`;

const MarketItem = styled(motion.div)<{ positive: boolean }>`
  background: ${props => props.theme.colors.glass};
  padding: 1.5rem;
  border-radius: ${props => props.theme.borderRadius.medium};
  border: 1px solid ${props => props.theme.colors.border};
  transition: ${props => props.theme.transitions.default};

  &:hover {
    border-color: ${props => props.positive ? props.theme.colors.success + '40' : props.theme.colors.danger + '40'};
    background: rgba(255, 255, 255, 0.05);
