          </NewsItem>
          <NewsItem to="/news">
            <h4>Commodity prices stabilize amid supply chain improvements</h4>
            <span>5 hours ago • WSJ</span>
          </NewsItem>
        </SidebarCard>
      </HeroSection>

      <MarketPulse />
       <MutualFunds />
     </HomeContainer>
   );
};

export default Home;
